// Binary search + linear interpolation for probe position
// Returns THREE.Vector3 in solarPivot space (scene units, pre-tilt)
function getProbePos(vd, year) {
  const traj = vd.trajectory;
  const t = year - 2000.0; // simTime

  if (t <= traj[0][0]) return new THREE.Vector3(traj[0][1], traj[0][2], traj[0][3]);

  // Beyond last data point: linear extrapolation using last two points
  if (t >= traj[traj.length-1][0]) {
    const last = traj[traj.length-1];
    const prev = traj[traj.length-2];
    const dt = last[0] - prev[0];
    const f = (t - last[0]) / dt;
    return new THREE.Vector3(
      last[1] + f * (last[1] - prev[1]),
      last[2] + f * (last[2] - prev[2]),
      last[3] + f * (last[3] - prev[3])
    );
  }
  let lo = 0, hi = traj.length - 1;
  while (hi - lo > 1) {
    const mid = (lo + hi) >> 1;
    if (traj[mid][0] <= t) lo = mid; else hi = mid;
  }
  const t0 = traj[lo], t1 = traj[hi];
  const f = (t - t0[0]) / (t1[0] - t0[0]);
  return new THREE.Vector3(
    t0[1] + f * (t1[1] - t0[1]),
    t0[2] + f * (t1[2] - t0[2]),
    t0[3] + f * (t1[3] - t0[3])
  );
}

